import static java.lang.Math.*;

public class Noise {
  private int[] permutation;
  private double[] gradient;
  private double frequency = 1;
  private double amplitude = 1;

  public Noise() {
    permutation = new int[256];
    for (int i = 0; i < 256; i++) {
      permutation[i] = i;
    }

    gradient = new double[256];
    for (int i = 0; i < 256; i++) {
      gradient[i] = rand.nextDouble() * 2 - 1;
    }
  }

  public void setFrequency(double frequency) {
    this.frequency = frequency;
  }

  public double getNoise(double x, double y) {
    int i = (int) (x / frequency);
    int j = (int) (y / frequency);
    int index = permutation[i + permutation[j]] % 32;
    return amplitude * gradient[index];
    // this line is commented out to test the noise function, but it will not be part of the actual noise function
    /*
    if (rand.nextDouble() < 0.5) {
      return 1;
    } else {
      return -1;
    }*/
  }
}

