public class Quaternion {
    private float x;
    private float y;
    private float z;
    private float w;

    public Quaternion(float x, float y, float z, float w) {
        this.x = x;
        this.y = y;
        this.z = z;
        this.w = w;
    }

    public Quaternion sub(Quaternion r) {
        return new Quaternion(w - r.getW(), x - r.getX(), y - r.getY(), z - r.getZ());
    }
}

